// Validate and extract GET query params: ?paper_id=XXX&label=relevant
const q = $input.first().json.query || {};
const paper_id = (q.paper_id || '').trim();
const label    = (q.label    || '').trim().toLowerCase();
const valid    = ['relevant', 'irrelevant', 'uncertain'];
if (!paper_id)          throw new Error('Missing paper_id parameter');
if (!valid.includes(label)) throw new Error('Invalid label: ' + label + '. Must be one of: ' + valid.join(', '));
return [{ json: { paper_id, label } }];

