// Build confirmation HTML page + Telegram message
const stats  = $input.first().json;
const params = $('Code - Validate Params').first().json;

const humanCount     = parseInt(stats.human_count     || 0);
const autoCount      = parseInt(stats.auto_count      || 0);
const pendingCount   = parseInt(stats.pending_count   || 0);
const humanRelevant  = parseInt(stats.human_relevant  || 0);
const humanIrrelevant= parseInt(stats.human_irrelevant|| 0);
const humanUncertain = parseInt(stats.human_uncertain || 0);

const label     = params.label;
const paper_id  = params.paper_id;
const emoji     = { relevant: '✅', irrelevant: '❌', uncertain: '🤔' }[label] || '📌';
const milestone = humanCount > 0 && humanCount % 10 === 0;

// Telegram notification text
const milestoneBlock = milestone
  ? `\n\n🎯 <b>Milestone: ${humanCount} human labels!</b>\nActive learning loop ready — queue WF6 retraining.`
  : '';
const telegramText = [
  `${emoji} <b>Label saved: ${label}</b>`,
  '',
  '📊 <b>Label stats</b>',
  `👤 Human: ${humanCount}  (✅${humanRelevant} ❌${humanIrrelevant} 🤔${humanUncertain})`,
  `🤖 Auto: ${autoCount}  |  ⏳ Pending: ${pendingCount}`,
  milestoneBlock
].join('\n');

// HTML confirmation page (styled, mobile-friendly)
const milestoneHtml = milestone
  ? `<div style="margin-top:12px;padding:10px;background:#FFF8E1;border-radius:8px;color:#D4A843;font-weight:bold;font-size:13px">🎯 Milestone: ${humanCount} human labels!</div>`
  : '';
const html = `<!DOCTYPE html>
<html><head><meta name="viewport" content="width=device-width,initial-scale=1"><title>Label Saved</title></head>
<body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;background:#F0F4F8;display:flex;justify-content:center;align-items:center;min-height:100vh;margin:0">
  <div style="background:white;border-radius:20px;padding:36px 28px;max-width:360px;width:90%;box-shadow:0 8px 24px rgba(0,0,0,0.1);text-align:center">
    <div style="font-size:56px;margin-bottom:12px">${emoji}</div>
    <h2 style="color:#1B3A5C;margin:0 0 6px;font-size:22px">Label Saved!</h2>
    <p style="font-size:18px;color:#333;margin:0 0 20px"><b>${label}</b></p>
    <div style="background:#F7FAFC;border-radius:10px;padding:14px;font-size:13px;color:#555;text-align:left">
      <div style="display:flex;justify-content:space-between;margin-bottom:6px">
        <span>👤 Human labels</span><b>${humanCount}</b>
      </div>
      <div style="display:flex;justify-content:space-between;margin-bottom:6px">
        <span>🤖 Auto labels</span><b>${autoCount}</b>
      </div>
      <div style="display:flex;justify-content:space-between">
        <span>⏳ Pending review</span><b>${pendingCount}</b>
      </div>
    </div>
    ${milestoneHtml}
    <p style="color:#AAB;font-size:12px;margin-top:20px">You can close this tab.</p>
  </div>
</body></html>`;

return [{ json: { html, telegramText, label, paper_id, human_count: humanCount, is_milestone: milestone } }];
